  //link to analyzer
  out.println("<div style='cursor:pointer;font-size:14px;text-align:right;margin:5px 15px 0 0;float:right;' onclick=\"window.open('/sims/designHistoryAnalyzer.jsp?a="+apname+"&p="+path+"&fn="+formName+"&ft="+formType+(formLevel==null?"":"&level="+formLevel)+"','_blank');\"><i class='fas fa-chart-line'></i></a></div>");

